int sumOfSquares(int n)
{
    int sum = 0;
    while (n > 0)
    {
        int digit = n % 10;
        sum += digit * digit;
        n /= 10;
    }
    return sum;
}

bool isHappy(int n)
{
    for (int i = 0; i < 1000; i++) // arbitrary cap — not a guarantee
    {
        if (n == 1) return true;
        n = sumOfSquares(n);
    }
    return false;
}

int main()
{
    cout << (isHappy(19) ? "true" : "false") << endl;

    return 0;
}

