    while (n > 0)
    {
        int digit = n % 10;
        sum += digit * digit;
        n /= 10;
    }
    return sum;
}

bool isHappy(int n)
{
    unordered_set<int> seen;

    while (n != 1 && !seen.count(n))
    {
        seen.insert(n);
        n = sumOfSquares(n);
    }

    return n == 1;
}

